// Package sagraphql is the hand-authored GraphQL client for the StackAdapt
// Public API (https://api.stackadapt.com/graphql). The generated HTTP client
// is REST-shaped; StackAdapt is a single GraphQL POST endpoint, so the typed
// read commands and novel analysis commands talk to the API through this
// client instead. Read-only by design — it only sends queries, never mutations.
//
// Durable hand-authored package (no "Generated by CLI Printing Press" header);
// preserved across `generate --force`.
package sagraphql

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"
)

// DefaultEndpoint is the StackAdapt production GraphQL endpoint.
const DefaultEndpoint = "https://api.stackadapt.com/graphql"

// Client executes GraphQL queries against StackAdapt with a bearer token.
type Client struct {
	token    string
	endpoint string
	http     *http.Client
}

// New builds a client. endpoint may be empty to use DefaultEndpoint.
func New(token, endpoint string) *Client {
	if endpoint == "" {
		endpoint = DefaultEndpoint
	}
	return &Client{
		token:    token,
		endpoint: endpoint,
		http:     &http.Client{Timeout: 60 * time.Second},
	}
}

type graphQLError struct {
	Message string `json:"message"`
}

type graphQLResponse struct {
	Data   json.RawMessage `json:"data"`
	Errors []graphQLError  `json:"errors"`
}

// Query executes a GraphQL query with optional variables and returns the raw
// `data` payload. GraphQL-level errors, HTTP errors, and rate limits are
// surfaced as Go errors. Retries once on HTTP 429 with a short backoff.
func (c *Client) Query(ctx context.Context, query string, variables map[string]any) (json.RawMessage, error) {
	if strings.TrimSpace(c.token) == "" {
		return nil, fmt.Errorf("no StackAdapt token: set STACKADAPT_API_TOKEN (a GraphQL API token, not the legacy REST key)")
	}
	body, err := json.Marshal(map[string]any{"query": query, "variables": variables})
	if err != nil {
		return nil, fmt.Errorf("marshaling query: %w", err)
	}

	for attempt := 0; attempt < 2; attempt++ {
		req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.endpoint, bytes.NewReader(body))
		if err != nil {
			return nil, err
		}
		req.Header.Set("Authorization", "Bearer "+c.token)
		req.Header.Set("Content-Type", "application/json")
		req.Header.Set("Accept", "application/json")

		resp, err := c.http.Do(req)
		if err != nil {
			return nil, fmt.Errorf("StackAdapt request failed: %w", err)
		}
		raw, readErr := io.ReadAll(io.LimitReader(resp.Body, 32<<20))
		_ = resp.Body.Close()
		if readErr != nil {
			return nil, fmt.Errorf("reading response: %w", readErr)
		}

		switch {
		case resp.StatusCode == http.StatusTooManyRequests:
			if attempt == 0 {
				// Context-aware backoff: a cancelled context (--timeout
				// deadline, Ctrl+C, agent session cut) must abort the wait
				// immediately instead of blocking the full 2s.
				select {
				case <-ctx.Done():
					return nil, ctx.Err()
				case <-time.After(2 * time.Second):
				}
				continue
			}
			return nil, fmt.Errorf("StackAdapt rate limit (HTTP 429): retry after a moment or narrow the date window")
		case resp.StatusCode == http.StatusUnauthorized || resp.StatusCode == http.StatusForbidden:
			return nil, fmt.Errorf("StackAdapt auth failed (HTTP %d): check STACKADAPT_API_TOKEN is a valid GraphQL token", resp.StatusCode)
		case resp.StatusCode >= 400:
			return nil, fmt.Errorf("StackAdapt HTTP %d: %s", resp.StatusCode, truncate(string(raw), 300))
		}

		var gr graphQLResponse
		if err := json.Unmarshal(raw, &gr); err != nil {
			return nil, fmt.Errorf("decoding GraphQL response: %w", err)
		}
		if len(gr.Errors) > 0 {
			msgs := make([]string, 0, len(gr.Errors))
			for _, e := range gr.Errors {
				msgs = append(msgs, e.Message)
			}
			return nil, fmt.Errorf("StackAdapt GraphQL error: %s", strings.Join(msgs, "; "))
		}
		return gr.Data, nil
	}
	return nil, fmt.Errorf("StackAdapt request failed after retry")
}

func truncate(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n] + "…"
}
